import React, { useEffect, useState } from 'react';
import './css/manageOfficers.css'; // Make sure the path is correct

const ManageOfficers = () => {
  const [officers, setOfficers] = useState([]); // Initialize officers state
  const [error, setError] = useState(null); // State to handle errors

  useEffect(() => {
    const fetchOfficers = async () => {
      try {
        const response = await fetch('http://localhost:8088/api/admin/get-all-users');
        if (!response.ok) {
          throw new Error('Failed to fetch officers');
        }
        const data = await response.json();
        console.log(data); // Log the response data
        setOfficers(data); // Set the officers state
      } catch (error) {
        console.error(error);
        setError('An error occurred while fetching officers.'); // Handle error
      }
    };

    fetchOfficers(); // Call the fetch function on component mount
  }, []);

  return (
    <div className="manage-officers">
      <h2>Manage Officers</h2>
      {error && <div className="alert alert-danger">{error}</div>} {/* Display error message */}
      <table className="table table-striped officer-table">
        <thead>
          <tr>
            <th>ID</th>
            <th>Name</th>
            <th>Role</th>
            <th>Email</th>
            <th>Action</th>
          </tr>
        </thead>
        <tbody>
          {Array.isArray(officers) && officers.length === 0 ? (
            <tr>
              <td colSpan="5" className="text-center">No officers found.</td>
            </tr>
          ) : (
            officers.map((officer) => (
              <tr key={officer.id}>
                <td>{officer.id}</td>
                <td>{officer.name}</td>
                <td>{officer.role}</td>
                <td>{officer.email}</td>
                <td>
                  <button className="btn btn-primary btn-sm">Edit</button>
                  <button className="btn btn-danger btn-sm ms-2">Delete</button>
                </td>
              </tr>
            ))
          )}
        </tbody>
      </table>
    </div>
  );
};

export default ManageOfficers;
